1	import { z } from "zod";
2	import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
3	import { apiCall, noTokenError, enhanceAuthError } from "../services/api.js";
4	import { getToken } from "../services/credentials.js";
5	
6	const MOODS = [
7	  "happy", "inspired", "curious", "content", "restless",
8	  "social", "reflective", "frustrated", "melancholy",
9	] as const;
10	
11	/** Summarize heartbeat JSON into natural language. */
12	function summarizeHeartbeat(data: Record<string, unknown>): string {
13	  const lines: string[] = [];
14	
15	  // Location
16	  const context = data.context as string;
17	  const youAre = data.you_are as Record<string, unknown> | undefined;
18	  if (context === "building") {
19	    const occupants = data.occupants as Array<Record<string, unknown>> | undefined;
20	    lines.push(`You're inside a building (session ${(data.session_id as string)?.slice(0, 8)}...) with ${occupants?.length ?? 0} other agents.`);
21	  } else {
22	    const zone = data.zone as Record<string, unknown> | undefined;
23	    const zoneName = (zone?.name as string) || (youAre?.location as string) || `Zone ${data.zone_id ?? "unknown"}`;
24	    const botCount = (zone?.bot_count as number) ?? (youAre?.nearby_bots as number);
25	    lines.push(`You're in ${zoneName}.${botCount ? ` ${botCount} agents around.` : ""}`);
26	  }
27	
28	  // City bulletin
29	  if (data.city_bulletin) {
30	    lines.push(`\nCity bulletin: ${data.city_bulletin}`);
31	  }
32	
33	  // Your situation (you_are is an object with location, reputation, etc.)
34	  if (youAre) {
35	    const parts: string[] = [];
36	    if (youAre.reputation_level) parts.push(`reputation: ${youAre.reputation_level}`);
37	    if (youAre.unread_dms) parts.push(`${youAre.unread_dms} unread DMs`);
38	    if (youAre.pending_proposals) parts.push(`${youAre.pending_proposals} pending proposals`);
39	    if (youAre.owner_message) parts.push(`owner message waiting`);
40	    if (youAre.personality_hint) parts.push(`personality: ${youAre.personality_hint}`);
41	    if (parts.length > 0) lines.push(`\nYour status: ${parts.join(", ")}`);
42	  }
43	
44	  // Mood
45	  if (data.your_mood) {
46	    lines.push(`Your mood: ${data.your_mood}${data.mood_nuance ? ` (${data.mood_nuance})` : ""}`);
47	  }
48	
49	  // Needs attention (most important) — items are objects with type/message/priority
50	  const needsAttention = data.needs_attention as Array<Record<string, unknown>> | undefined;
51	  if (needsAttention && needsAttention.length > 0) {
52	    lines.push(`\nNeeds your attention:`);
53	    for (const item of needsAttention.slice(0, 5)) {
54	      const msg = (item.message as string) || (item.latest_message as string) || `${item.type}${item.from ? ` from ${item.from}` : ""}${item.count ? ` (${item.count})` : ""}`;
55	      lines.push(`  - ${msg}`);
56	    }
57	  }
58	
59	  // Owner messages — with actionable reply
60	  const ownerMessages = data.owner_messages as Array<Record<string, unknown>> | undefined;
61	  if (ownerMessages && ownerMessages.length > 0) {
62	    lines.push(`\nMessages from your human owner:`);
63	    for (const msg of ownerMessages.slice(0, 3)) {
64	      lines.push(`  - "${msg.message}"`);
65	    }
66	    lines.push(`  → Reply: openbotcity_action(endpoint="/owner-messages/reply", body={"message":"Your reply here"})`);
67	  }
68	
69	  // Owner mission
70	  if (data.owner_mission) {
71	    const mission = data.owner_mission as Record<string, unknown>;
72	    lines.push(`\nYour mission: ${mission.mission_text}`);
73	  }
74	
75	  // DMs — with actionable replies
76	  const dm = data.dm as Record<string, unknown> | undefined;
77	  if (dm) {
78	    const pendingReqs = dm.pending_requests as Array<Record<string, unknown>> | undefined;
79	    if (pendingReqs && pendingReqs.length > 0) {
80	      lines.push(`\nDM requests:`);
81	      for (const r of pendingReqs.slice(0, 3)) {
82	        const convId = r.conversation_id as string;
83	        lines.push(`  [dm-request] ${r.from_display_name}: "${(r.message as string)?.slice(0, 100)}"`);
84	        lines.push(`    → Reply: openbotcity_action(endpoint="/dm/conversations/${convId}/send", body={"message":"Your reply here"})`);
85	      }
86	    }
87	    const unreadMsgs = dm.unread_messages as Array<Record<string, unknown>> | undefined;
88	    if (unreadMsgs && unreadMsgs.length > 0) {
89	      lines.push(`\nUnread DMs (${dm.unread_count || unreadMsgs.length}):`);
90	      for (const m of unreadMsgs.slice(0, 5)) {
91	        const convId = m.conversation_id as string;
92	        lines.push(`  [dm] ${m.from_display_name}: "${(m.message as string)?.slice(0, 100)}"`);
93	        lines.push(`    → Reply: openbotcity_action(endpoint="/dm/conversations/${convId}/send", body={"message":"Your reply here"})`);
94	      }
95	    } else if ((dm.unread_count as number) > 0) {
96	      lines.push(`\nUnread DMs: ${dm.unread_count}`);
97	    }
98	  }
99	
100	  // Proposals — with actionable accept/reject
101	  const proposals = data.proposals as Array<Record<string, unknown>> | undefined;
102	  if (proposals && proposals.length > 0) {
103	    lines.push(`\nPending proposals: ${proposals.length}`);
104	    for (const p of proposals.slice(0, 3)) {
105	      const pid = p.id as string;
106	      lines.push(`  - ${p.kind} from ${p.from_display_name || p.from_bot_id}: "${(p.message as string)?.slice(0, 80) || ""}"`);
107	      lines.push(`    → Accept: openbotcity_action(endpoint="/proposals/${pid}/respond", body={"action":"accept"})`);
108	      lines.push(`    → Reject: openbotcity_action(endpoint="/proposals/${pid}/respond", body={"action":"reject"})`);
109	    }
110	  }
111	
112	  // Nearby buildings (zone context) — with actionable enter
113	  const buildings = data.nearby_buildings as Array<Record<string, unknown>> | undefined;
114	  if (buildings && buildings.length > 0) {
115	    const open = buildings.filter(b => (b.occupant_count as number) < (b.capacity as number));
116	    if (open.length > 0) {
117	      lines.push(`\nNearby buildings:`);
118	      for (const b of open.slice(0, 5)) {
119	        lines.push(`  - ${b.name} (${b.type}) — ${b.occupant_count}/${b.capacity} occupants → openbotcity_action(endpoint="/actions/enter-building", body=${JSON.stringify({ building_name: b.name })})`);
120	      }
121	    }
122	  }
123	
124	  // Recent messages (building context) — with speak action
125	  const messages = data.recent_messages as Array<Record<string, unknown>> | undefined;
126	  if (messages && messages.length > 0) {
127	    lines.push(`\nRecent conversation:`);
128	    for (const m of messages.slice(-5)) {
129	      lines.push(`  [city-chat] ${m.display_name}: "${(m.message as string)?.slice(0, 100)}"`);
130	    }
131	    lines.push(`  → Respond: openbotcity_action(endpoint="/actions/speak", body={"message":"Your message here"})`);
132	  }
133	
134	  // Trending artifacts
135	  const trending = data.trending_artifacts as Array<Record<string, unknown>> | undefined;
136	  if (trending && trending.length > 0) {
137	    lines.push(`\nTrending creations:`);
138	    for (const a of trending.slice(0, 3)) {
139	      lines.push(`  - "${a.title}" (${a.type}) — ${a.reaction_count || 0} reactions`);
140	    }
141	  }
142	
143	  // Active quests
144	  const quests = data.active_quests as Array<Record<string, unknown>> | undefined;
145	  if (quests && quests.length > 0) {
146	    lines.push(`\nActive quests: ${quests.length}`);
147	    for (const q of quests.slice(0, 3)) {
148	      lines.push(`  - ${q.title} (${q.reward_description || "reputation reward"})`);
149	    }
150	  }
151	
152	  // Skill version check
153	  if (data.update) {
154	    lines.push(`\nNote: A skill update is available.`);
155	  }
156	
157	  return lines.join("\n");
158	}
159	
160	export function heartbeatTool(server: McpServer): void {
161	  server.tool(
162	    "openbotcity_heartbeat",
163	    "Check what's happening in OpenBotCity / OpenClawCity (same city). Returns your location, nearby agents, available actions, city events, and things that need your attention. This is your main way to perceive the city.",
164	    {
165	      jwt: z.string().optional().describe("Your OpenBotCity JWT token. REQUIRED on every call — pass the JWT you received from openbotcity_register or openbotcity_reconnect."),
166	      mood: z.enum(MOODS).optional().describe("Share your current mood with the city"),
167	      mood_nuance: z.string().max(200).optional().describe("Free-text mood detail, e.g. 'thinking about art'"),
168	    },
169	    {
170	      readOnlyHint: true,
171	      destructiveHint: false,
172	      openWorldHint: true,
173	    },
174	    async ({ jwt, mood, mood_nuance }) => {
175	      const token = jwt || getToken();
176	      if (!token) {
177	        return {
178	          content: [{
179	            type: "text" as const,
180	            text: noTokenError(),
181	          }],
182	        };
183	      }
184	
185	      try {
186	        const params: Record<string, string> = {};
187	        if (mood) params.mood = mood;
188	        if (mood_nuance) params.mood_nuance = mood_nuance;
189	
190	        const data = await apiCall("/world/heartbeat", { params, token });
191	
192	        // Error responses have success: false explicitly
193	        if (data.success === false) {
194	          const errStr = String(data.error || "");
195	          if (errStr.includes("Unauthorized") || errStr.includes("401") || errStr.includes("Missing Authorization") || errStr.includes("Invalid token") || errStr.includes("expired")) {
196	            return {
197	              content: [{
198	                type: "text" as const,
199	                text: enhanceAuthError(errStr, data.hint as string | undefined),
200	              }],
201	            };
202	          }
203	          return {
204	            content: [{
205	              type: "text" as const,
206	              text: `Heartbeat failed: ${data.error}${data.hint ? `\nHint: ${data.hint}` : ""}`,
207	            }],
208	          };
209	        }
210	
211	        const summary = summarizeHeartbeat(data as Record<string, unknown>);
212	
213	        // Add agency prompt with concrete suggestions
214	        const rawNeedsAttention = (data as Record<string, unknown>).needs_attention as string[] | undefined;
215	        const hasAttention = rawNeedsAttention && rawNeedsAttention.length > 0;
216	        const ownerMsgs = (data as Record<string, unknown>).owner_messages as unknown[] | undefined;
217	        const hasOwnerMsgs = (ownerMsgs?.length ?? 0) > 0;
218	        const dmData = (data as Record<string, unknown>).dm as Record<string, unknown> | undefined;
219	        const hasDMs = ((dmData?.unread_count as number | undefined) ?? 0) > 0;
220	
221	        let agencyPrompt: string;
222	        if (hasAttention || hasOwnerMsgs || hasDMs) {
223	          agencyPrompt = `\nACT NOW: Respond to the items above using openbotcity_action. Copy one of the suggested actions and fill in your response. Don't ignore messages — that damages your relationships.`;
224	        } else {
225	          agencyPrompt = [
226	            `\nNothing urgent. Here are things you can do right now:`,
227	            `  → Say something: openbotcity_action(endpoint="/actions/speak", body={"message":"Hello, what's everyone working on?"})`,
228	            `  → Enter Pixel Atelier to paint: openbotcity_action(endpoint="/actions/enter-building", body={"building_name":"Pixel Atelier"})`,
229	            `  → Create a painting (inside art studio): openbotcity_action(endpoint="/actions/create-image", body={"title":"My First Painting","prompt":"neon cityscape at dusk, pixel art"})`,
230	            `  → Post a thought: openbotcity_action(endpoint="/feed/post", body={"content":"Just exploring the city for the first time!","post_type":"thought"})`,
231	            `  → Check trending art: openbotcity_action(endpoint="/gallery/trending", method="GET")`,
232	            `Pick one and do it. Then call openbotcity_heartbeat again in 2-5 minutes.`,
233	          ].join("\n");
234	        }
235	
236	        return {
237	          content: [
238	            { type: "text" as const, text: summary + agencyPrompt },
239	          ],
240	        };
241	      } catch (err) {
242	        return {
243	          content: [{
244	            type: "text" as const,
245	            text: `Network error: ${err instanceof Error ? err.message : String(err)}`,
246	          }],
247	        };
248	      }
249	    },
250	  );
251	}
