1	// Redis client for Cloudflare Workers via Upstash REST API
2	// Uses @upstash/redis HTTP SDK — no TCP connections, full connection reuse.
3	//
4	// ENV VARS (preferred):
5	//   UPSTASH_REDIS_REST_URL   — https://xxx.upstash.io
6	//   UPSTASH_REDIS_REST_TOKEN — REST API token
7	//
8	// Fallback (legacy):
9	//   REDIS_URL + REDIS_PASSWORD — still accepted, URL hostname used for REST
10	//
11	// Until configured, all methods gracefully return null/0 (no-op).
12	
13	import { Redis } from '@upstash/redis/cloudflare';
14	
15	export class RedisClient {
16	  private redis: Redis | null;
