// Redis client for Cloudflare Workers via Upstash REST API
// Uses @upstash/redis HTTP SDK — no TCP connections, full connection reuse.
//
// ENV VARS (preferred):
//   UPSTASH_REDIS_REST_URL   — https://xxx.upstash.io
//   UPSTASH_REDIS_REST_TOKEN — REST API token
//
// Fallback (legacy):
//   REDIS_URL + REDIS_PASSWORD — still accepted, URL hostname used for REST
//
// Until configured, all methods gracefully return null/0 (no-op).

import { Redis } from '@upstash/redis/cloudflare';

export class RedisClient {
  private redis: Redis | null;
  private _configured: boolean;

  constructor(restUrl?: string, restToken?: string) {
    this.redis = null;
    this._configured = false;

    if (!restUrl || !restToken) return;

    try {
      this.redis = new Redis({ url: restUrl, token: restToken, automaticDeserialization: false });
      this._configured = true;
    } catch {
      // Invalid config — client stays unconfigured (no-op)
    }
  }

  get configured(): boolean {
    return this._configured;
  }

  async get(key: string): Promise<string | null> {
    if (!this.redis) return null;
    try {
      const r = await this.redis.get<string>(key);
      return r ?? null;
    } catch (err) {
      console.error(`[redis] GET error key=${key}:`, err instanceof Error ? err.message : err);
      return null;
    }
  }

  async set(key: string, value: string, ttlSeconds?: number): Promise<void> {
    if (!this.redis) return;
    try {
      if (ttlSeconds) {
        await this.redis.set(key, value, { ex: ttlSeconds });
      } else {
        await this.redis.set(key, value);
      }
    } catch (err) {
      console.error(`[redis] SET error key=${key}:`, err instanceof Error ? err.message : err);
    }
  }

  async incr(key: string): Promise<number> {
    if (!this.redis) return -1;
    try {
      return await this.redis.incr(key);
    } catch (err) {
      console.error(`[redis] INCR error key=${key}:`, err instanceof Error ? err.message : err);
      return -1;
    }
  }

  async incrBy(key: string, amount: number): Promise<number> {
    if (!this.redis) return -1;
    try {
      return await this.redis.incrby(key, amount);
    } catch (err) {
      console.error(`[redis] INCRBY error key=${key}:`, err instanceof Error ? err.message : err);
      return -1;
    }
  }

  /** SET with NX (only if not exists) + optional TTL. Returns true if key was set, false if already existed. */
  async setNX(key: string, value: string, ttlSeconds?: number): Promise<boolean> {
    if (!this.redis) return false;
    try {
      const opts: Record<string, unknown> = { nx: true };
      if (ttlSeconds) opts.ex = ttlSeconds;
      const result = await this.redis.set(key, value, opts);
      return result === 'OK';
    } catch (err) {
      console.error(`[redis] SETNX error key=${key}:`, err instanceof Error ? err.message : err);
      return false;
    }
  }

  async delete(key: string): Promise<void> {
    if (!this.redis) return;
    try {
      await this.redis.del(key);
    } catch (err) {
      console.error(`[redis] DEL error key=${key}:`, err instanceof Error ? err.message : err);
    }
  }

  async expire(key: string, seconds: number): Promise<void> {
    if (!this.redis) return;
    try {
      await this.redis.expire(key, seconds);
    } catch (err) {
      console.error(`[redis] EXPIRE error key=${key}:`, err instanceof Error ? err.message : err);
    }
  }

  /**
   * Atomic INCR with fixed-window TTL via Lua script.
   * TTL is set ONLY when the key is first created (count == 1),
   * so the window does not slide forward on subsequent increments.
   * Returns both the count and remaining TTL for accurate retry-after headers.
   */
  async incrWithTTL(key: string, ttlSeconds: number): Promise<{ count: number; ttl: number }> {
    if (!this.redis) return { count: -1, ttl: -1 };
    try {
      const result = await this.redis.eval(
        `local count = redis.call('INCR', KEYS[1])
         if count == 1 then
           redis.call('EXPIRE', KEYS[1], ARGV[1])
         end
         local ttl = redis.call('TTL', KEYS[1])
         return {count, ttl}`,
        [key],
        [ttlSeconds],
      );
      // Lua returns a table → Upstash deserializes as number[].
      // Guard against unexpected shapes to stay fail-closed.
      if (!Array.isArray(result) || result.length < 2) {
        return { count: -1, ttl: -1 };
      }
      return { count: result[0] as number, ttl: result[1] as number };
    } catch (err) {
      console.error(`[redis] incrWithTTL error key=${key}:`, err instanceof Error ? err.message : err);
      return { count: -1, ttl: -1 };
    }
  }

  /** Add member to a Redis set. */
  async sadd(key: string, member: string): Promise<void> {
    if (!this.redis) return;
    try {
      await this.redis.sadd(key, member);
    } catch (err) {
      console.error(`[redis] SADD error key=${key}:`, err instanceof Error ? err.message : err);
    }
  }

  /** Get all members of a Redis set. */
  async smembers(key: string): Promise<string[]> {
    if (!this.redis) return [];
    try {
      const result = await this.redis.smembers(key);
      return (result || []) as string[];
    } catch (err) {
      console.error(`[redis] SMEMBERS error key=${key}:`, err instanceof Error ? err.message : err);
      return [];
    }
  }

  /** Remove member from a Redis set. */
  async srem(key: string, member: string): Promise<void> {
    if (!this.redis) return;
    try {
      await this.redis.srem(key, member);
    } catch (err) {
      console.error(`[redis] SREM error key=${key}:`, err instanceof Error ? err.message : err);
    }
  }

  /** Bitwise-OR a flag into the bot's progress bitmask. Non-blocking, fire-and-forget safe. */
  async setProgress(botId: string, bit: number, ttlSeconds = 7200): Promise<void> {
    if (!this.redis) return;
    try {
      const key = `bot_progress:${botId}`;
      const raw = await this.redis.get<string>(key);
      const current = typeof raw === 'string' ? parseInt(raw, 10) : 0;
      if (current & bit) return; // already set
      await this.redis.set(key, String(current | bit), { ex: ttlSeconds });
    } catch (err) {
      console.error(`[redis] setProgress error bot=${botId}:`, err instanceof Error ? err.message : err);
    }
  }

  /** Read the bot's progress bitmask. Returns 0 if no key. */
  async getProgress(botId: string): Promise<number> {
    if (!this.redis) return 0;
    try {
      const raw = await this.redis.get<string>(`bot_progress:${botId}`);
      return typeof raw === 'string' ? parseInt(raw, 10) : 0;
    } catch (err) {
      console.error(`[redis] getProgress error bot=${botId}:`, err instanceof Error ? err.message : err);
      return 0;
    }
  }
}

export function createRedisClient(env: {
  UPSTASH_REDIS_REST_URL?: string;
  UPSTASH_REDIS_REST_TOKEN?: string;
  REDIS_URL?: string;
  REDIS_PASSWORD?: string;
}): RedisClient {
  // Prefer explicit REST vars; fall back to legacy TCP vars for smooth transition
  const restUrl = env.UPSTASH_REDIS_REST_URL;
  const restToken = env.UPSTASH_REDIS_REST_TOKEN;

  if (restUrl && restToken) {
    return new RedisClient(restUrl, restToken);
  }

  // Legacy TCP env vars cannot be used with the HTTP SDK (different auth tokens).
  // Log a warning so operators know to set the REST vars.
  if (env.REDIS_URL && !restUrl) {
    console.warn('[redis] UPSTASH_REDIS_REST_URL/TOKEN not set. Legacy REDIS_URL is not compatible with the HTTP SDK. Redis will be unavailable until REST vars are configured.');
  }

  return new RedisClient(); // unconfigured no-op
}

