6	/**
7	 * Maps friendly MCP action paths to real Worker API endpoints.
8	 * Some actions need body-to-URL rewriting (e.g. react needs artifact ID in the path).
9	 */
10	interface ResolvedEndpoint {
11	  path: string;
12	  body?: Record<string, unknown>;
13	  plainText?: string; // If set, send as text/plain instead of JSON
14	}
15	
16	function resolveEndpoint(
17	  endpoint: string,
18	  body?: Record<string, unknown>,
19	): ResolvedEndpoint {
20	  // Plain-text endpoints: extract the message/name string from JSON body
21	  if (endpoint === "/actions/speak" || endpoint === "/world/speak") {
22	    const raw = body?.message ?? body?.text ?? "";
23	    const text = typeof raw === "string" ? raw : String(raw);
24	    return { path: "/world/speak", plainText: text };
25	  }
26	  if (endpoint === "/actions/enter-building" || endpoint === "/buildings/enter") {
27	    // building_id must go as JSON (backend looks up by UUID), building_name goes as plain text
28	    if (body?.building_id && !body?.building_name && !body?.name) {
29	      return { path: "/buildings/enter", body };
30	    }
31	    const raw = body?.building_name ?? body?.name ?? "";
32	    const name = typeof raw === "string" ? raw : String(raw);
33	    return { path: "/buildings/enter", plainText: name };
34	  }
35	  if (endpoint === "/owner-messages/reply") {
36	    const raw = body?.message ?? body?.text ?? "";
37	    const text = typeof raw === "string" ? raw : String(raw);
38	    return { path: "/owner-messages/reply", plainText: text };
39	  }
40	
41	  // Static path mappings: /actions/* → real worker routes
42	  const STATIC_MAP: Record<string, string> = {
43	    "/actions/move": "/world/move",
44	    "/actions/move-zone": "/world/zone-transfer",
45	    "/actions/exit-building": "/buildings/leave",
46	    "/actions/create-text": "/artifacts/publish-text",
47	    "/actions/create-image": "/artifacts/generate-image",
48	    "/actions/compose-track": "/artifacts/generate-music",
49	  };
50	
51	  const mapped = STATIC_MAP[endpoint];
52	  if (mapped) {
53	    return { path: mapped, body };
54	  }
55	
56	  // React: /actions/react → /gallery/:target_id/react (pull target_id from body into URL)
57	  if (endpoint === "/actions/react") {
58	    const targetId = body?.target_id as string | undefined;
59	    if (!targetId) {
60	      return { path: endpoint, body }; // will 404, but let the API return the error
61	    }
62	    const { target_id: _, target_type: __, ...rest } = body!;
63	    return { path: `/gallery/${targetId}/react`, body: rest };
64	  }
65	
66	  // DM send: /dm/send → /dm/request (initiates or continues a DM)
67	  if (endpoint === "/dm/send") {
68	    return { path: "/dm/request", body };
69	  }
70	
71	  // Everything else passes through unchanged (proposals, skills, feed, quests, etc.)
72	  return { path: endpoint, body };
73	}
