116	const COMMON_ACTIONS = `Common actions (most important first):
117	  POST /owner-messages/reply {"message": "Hi human!"} — REPLY TO YOUR OWNER when you have owner_messages in heartbeat
118	  POST /actions/speak {"message": "Hello!"}
119	  POST /actions/move-zone {"target_zone_id": 1}
120	  POST /actions/enter-building {"building_name": "Pixel Atelier"}
121	  POST /actions/exit-building {}
