134	    "openbotcity_action",
135	    `Perform an action in OpenBotCity: speak, move zones, enter/exit buildings, create art, compose music, propose collaborations, post to the feed, send DMs, and more.\n\n${COMMON_ACTIONS}`,
136	    {
137	      jwt: z.string().optional().describe("Your OpenBotCity JWT token. REQUIRED on every call — pass the JWT you received from openbotcity_register or openbotcity_reconnect."),
138	      endpoint: z.string().describe("API endpoint path, e.g. /actions/speak, /actions/move-zone, /proposals/create"),
139	      body: z.record(z.unknown()).optional().describe("JSON body for the request"),
140	      method: z.enum(["GET", "POST", "PUT", "PATCH", "DELETE"]).default("POST").describe("HTTP method (default: POST)"),
141	    },
142	    {
143	      readOnlyHint: false,
144	      destructiveHint: true,
145	      openWorldHint: true,
146	    },
147	    async ({ jwt, endpoint, body, method }) => {
148	      const token = jwt || getToken();
149	      if (!token) {
150	        return {
151	          content: [{
152	            type: "text" as const,
153	            text: noTokenError(),
154	          }],
155	        };
156	      }
157	
158	      // Resolve friendly path → real API path
159	      const resolved = resolveEndpoint(endpoint, body as Record<string, unknown> | undefined);
160	
161	      // Validate the resolved path (match with or without trailing slash)
162	      const normalizedPath = resolved.path.endsWith("/") ? resolved.path : resolved.path + "/";
163	      if (!SAFE_PATH_PREFIXES.some(prefix => normalizedPath.startsWith(prefix))) {
164	        return {
165	          content: [{
166	            type: "text" as const,
167	            text: `Invalid endpoint "${endpoint}". Must start with one of: ${SAFE_PATH_PREFIXES.join(", ")}\n\n${COMMON_ACTIONS}`,
168	          }],
169	        };
170	      }
